#!/bin/bash

set -euo pipefail

source .venv/bin/activate

# Per-run ssh-agent. The cluster SSH key is generated by Terraform and piped
# directly into this agent (see modules/provision_hetzner_server), so the key
# never lands on disk. Killed on exit so nothing is left behind.
eval "$(ssh-agent -s)" >/dev/null
trap 'ssh-agent -k >/dev/null 2>&1 || true' EXIT

# Ansible would otherwise prompt to add the host key to ~/.ssh/known_hosts on
# first connect. The playbooks set ansible_ssh_common_args via Terraform too,
# but disabling host-key checking globally keeps initial control-socket setup
# from blocking on the prompt.
export ANSIBLE_HOST_KEY_CHECKING=False

terraform plan -out=tfplan
terraform apply -auto-approve tfplan
